const VAR_LABELS   = { servis:'Servis uređaja', namestaj:'Popravka nameštaja', toalet:'Toaletni pribor', ciscenje:'Trošak čišćenja', ostalo:'Ostalo' };

// ── Inicijalizuj UI za izveštaje u profil tabu ───────────────────
export function setupReportUI(user) {
  const isMasterAdmin = user.email.toLowerCase() === ADMIN_EMAIL.toLowerCase();
  const isLandlord = !isMasterAdmin;
  
  let el = document.getElementById('reportSection');
  if (!el) {
    el = document.createElement('div');
    el.id = 'reportSection';
    // Ubaci pre about-card
    const about = document.querySelector('#profil .about-card');
    if (about) about.parentNode.insertBefore(el, about);
    else document.getElementById('profileUser').appendChild(el);
  }
  
  el.hidden = false;

  const periodFields = () => `
    <!-- Period -->
    <div class="report-field">
      <label class="report-label">Period</label>
      <div class="report-period-btns">
        <button class="rp-btn active" data-rp="month">Mesec</button>
        <button class="rp-btn" data-rp="quarter">Kvartal</button>
        <button class="rp-btn" data-rp="year">Godina</button>
        <button class="rp-btn" data-rp="custom">Custom</button>
      </div>
    </div>
    <div class="report-field" id="rpCustomDates" style="display:none">
      <label class="report-label">Raspon datuma</label>
      <div class="report-date-row">
        <input type="date" id="rpDateOd" class="report-date-input">
        <span style="color:var(--muted)">—</span>
        <input type="date" id="rpDateDo" class="report-date-input">
      </div>
    </div>
    <div class="report-field" id="rpMonthField">
      <label class="report-label">Mesec i godina</label>
      <div class="report-date-row">
        <input type="month" id="rpMonth" class="report-date-input" value="${new Date().toISOString().slice(0,7)}">
      </div>
    </div>
    <div class="report-field" id="rpQuarterField" style="display:none">
      <label class="report-label">Kvartal i godina</label>
      <div class="report-date-row">
        <select id="rpQuarter" class="report-date-input">
          <option value="1">Q1 (Jan–Mar)</option>
          <option value="2">Q2 (Apr–Jun)</option>
          <option value="3">Q3 (Jul–Sep)</option>
          <option value="4">Q4 (Okt–Dec)</option>
        </select>
        <input type="number" id="rpQuarterYear" class="report-date-input" value="${new Date().getFullYear()}" min="2020" max="2099" style="width:80px">
      </div>
    </div>
    <div class="report-field" id="rpYearField" style="display:none">
      <label class="report-label">Godina</label>
      <input type="number" id="rpYear" class="report-date-input" value="${new Date().getFullYear()}" min="2020" max="2099" style="width:100px">
    </div>
  `;

  const sekcijePicker = () => `
    <div class="report-field">
      <label class="report-label">Uključi u izveštaj</label>
      <div class="report-sections-grid">
        <label class="report-check"><input type="checkbox" id="rpSecZakupac" checked> Zakupac</label>
        <label class="report-check"><input type="checkbox" id="rpSecPrihodi" checked> Prihodi</label>
        <label class="report-check"><input type="checkbox" id="rpSecTroskovi" checked> Troškovi</label>
        <label class="report-check"><input type="checkbox" id="rpSecKvarovi" checked> Kvarovi</label>
        <label class="report-check"><input type="checkbox" id="rpSecPoruke"> Poruke</label>
      </div>
    </div>
  `;

  if (isMasterAdmin) {
    el.innerHTML = `
      <div class="report-card">
        <div class="report-card-header">
          <i class="ti ti-file-text"></i>
          <span>Generiši izveštaj — Master Admin</span>
        </div>
        <div class="report-body">
          ${periodFields()}
          <!-- Landlordovi -->
          <div class="report-field">
            <div class="report-label-row">
              <label class="report-label">Landlordovi</label>
              <button class="rp-select-all" id="rpSelectAllLandlords">Izaberi sve</button>
            </div>
            <div id="rpLandlordList" class="report-unit-list">
              <p class="info-text" style="font-size:13px">Učitavam landlordove...</p>
            </div>
          </div>
          <!-- Stanovi po landlordovima -->
          <div class="report-field" id="rpAdminUnitSection" style="display:none">
            <div class="report-label-row">
              <label class="report-label">Stanovi</label>
              <button class="rp-select-all" id="rpSelectAllUnits">Izaberi sve</button>
            </div>
            <div id="rpAdminUnitList" class="report-unit-list"></div>
          </div>
          ${sekcijePicker()}
          <button id="rpGenerateBtn" class="btn-primary" style="width:100%;margin-top:4px">
            <i class="ti ti-download"></i> Generiši PDF
          </button>
          <div id="rpStatus" style="font-size:13px;color:var(--muted);text-align:center;margin-top:8px;min-height:18px"></div>
        </div>
      </div>
    `;
    loadAdminLandlords(el);
  } else {
    el.innerHTML = `
      <div class="report-card">
        <div class="report-card-header">
          <i class="ti ti-file-text"></i>
          <span>Generiši izveštaj</span>
        </div>
        <div class="report-body">
          ${periodFields()}
          <div class="report-field">
            <div class="report-label-row">
              <label class="report-label">Stanovi</label>
              <button class="rp-select-all" id="rpSelectAllUnits">Izaberi sve</button>
            </div>
            <div id="rpUnitList" class="report-unit-list">
              <p class="info-text" style="font-size:13px">Učitavam stanove...</p>
            </div>
          </div>
          ${sekcijePicker()}
          <button id="rpGenerateBtn" class="btn-primary" style="width:100%;margin-top:4px">
            <i class="ti ti-download"></i> Generiši PDF
          </button>
          <div id="rpStatus" style="font-size:13px;color:var(--muted);text-align:center;margin-top:8px;min-height:18px"></div>
        </div>
      </div>
    `;
    loadReportUnits(user);

    // Izaberi sve stanove
    document.getElementById('rpSelectAllUnits').onclick = () => {
      const cbs = document.querySelectorAll('.rp-unit-cb');
      const allChecked = [...cbs].every(c => c.checked);
      cbs.forEach(c => c.checked = !allChecked);
    };
  }

  // Period prebacivanje
  let activePeriod = 'month';
  el.querySelectorAll('.rp-btn').forEach(btn => {
    btn.onclick = () => {
      el.querySelectorAll('.rp-btn').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      activePeriod = btn.dataset.rp;
      document.getElementById('rpMonthField').style.display   = activePeriod === 'month'   ? '' : 'none';
      document.getElementById('rpQuarterField').style.display = activePeriod === 'quarter' ? '' : 'none';
      document.getElementById('rpYearField').style.display    = activePeriod === 'year'    ? '' : 'none';
      document.getElementById('rpCustomDates').style.display  = activePeriod === 'custom'  ? '' : 'none';
    };
  });

  // Generiši
  document.getElementById('rpGenerateBtn').onclick = () => generateReport(user, activePeriod);
}

// ── Admin: učitaj landlordove i njihove stanove ──────────────────
async function loadAdminLandlords(el) {
  const landlordList = document.getElementById('rpLandlordList');
  try {
    const usersSnap = await getDocs(collection(db, 'users'));
    const unitsSnap = await getDocs(collection(db, 'units'));

    // Grupiši stanove po ownerId
    const unitsByOwner = {};
    unitsSnap.docs.forEach(d => {
      const oid = d.data().ownerId;
      if (!oid) return;
      if (!unitsByOwner[oid]) unitsByOwner[oid] = [];
      unitsByOwner[oid].push({ id: d.id, ...d.data() });
    });

    // Filtriraj samo korisnike koji imaju stanove
    const landlords = usersSnap.docs
      .filter(d => unitsByOwner[d.id])
      .map(d => ({ id: d.id, ...d.data() }));

    if (!landlords.length) {
      landlordList.innerHTML = '<p class="info-text" style="font-size:13px">Nema landlordova.</p>';
      return;
    }

    landlordList.innerHTML = landlords.map(l => `
      <label class="report-check">
        <input type="checkbox" class="rp-landlord-cb" value="${l.id}"
          data-name="${l.displayName || l.email || l.id}">
        ${l.displayName || l.email || l.id}
        <span style="color:var(--muted);font-size:11px">(${unitsByOwner[l.id].length} stan${unitsByOwner[l.id].length > 1 ? 'ova' : ''})</span>
      </label>
    `).join('');

    // Izaberi sve landlordove
    document.getElementById('rpSelectAllLandlords').onclick = () => {
      const cbs = document.querySelectorAll('.rp-landlord-cb');
      const allChecked = [...cbs].every(c => c.checked);
      cbs.forEach(c => c.checked = !allChecked);
      refreshAdminUnitList(unitsByOwner);
    };

    // Kada se klikne na landlorda, osveži listu stanova
    landlordList.addEventListener('change', () => refreshAdminUnitList(unitsByOwner));

    // Izaberi sve stanove
    document.getElementById('rpSelectAllUnits').onclick = () => {
      const cbs = document.querySelectorAll('.rp-unit-cb');
      const allChecked = [...cbs].every(c => c.checked);
      cbs.forEach(c => c.checked = !allChecked);
    };

  } catch(e) {
    landlordList.innerHTML = '<p class="info-text" style="font-size:13px;color:var(--red)">Greška pri učitavanju.</p>';
    console.error(e);
  }
}

function refreshAdminUnitList(unitsByOwner) {
  const selectedLandlords = [...document.querySelectorAll('.rp-landlord-cb:checked')].map(c => c.value);
  const section = document.getElementById('rpAdminUnitSection');
  const unitList = document.getElementById('rpAdminUnitList');

  if (!selectedLandlords.length) {
    section.style.display = 'none';
    return;
  }
  section.style.display = '';
  unitList.innerHTML = selectedLandlords.map(oid => {
    const units = unitsByOwner[oid] || [];
    const landlordName = document.querySelector(`.rp-landlord-cb[value="${oid}"]`)?.dataset.name || oid;
    return `
      <div class="rp-landlord-group">
        <div class="rp-landlord-group-header">
          <div class="rp-landlord-group-label">${landlordName}</div>
          <button class="rp-select-all rp-select-owner" data-owner="${oid}">Izaberi sve</button>
        </div>
        ${units.map(u => `
          <label class="report-check" style="padding-left:12px">
            <input type="checkbox" class="rp-unit-cb" value="${u.id}"
              data-name="${u.name}" data-owner="${oid}" data-owner-name="${landlordName}" checked>
            ${u.name}${u.adresa ? ' — ' + u.adresa : ''}
          </label>
        `).join('')}
      </div>
    `;
  }).join('');

  // Dodaj "Izaberi sve" onclick po landlordу
  unitList.querySelectorAll('.rp-select-owner').forEach(btn => {
    btn.onclick = () => {
      const oid = btn.dataset.owner;
      const cbs = unitList.querySelectorAll(`.rp-unit-cb[data-owner="${oid}"]`);
      const allChecked = [...cbs].every(c => c.checked);
      cbs.forEach(c => c.checked = !allChecked);
    };
  });
}

// ── Učitaj stanove za checkbox listu (landlord) ─────────────────
async function loadReportUnits(user) {
  const container = document.getElementById('rpUnitList');
  if (!container) return;
  try {
    const snap = await getDocs(query(collection(db, 'units'), where('ownerId', '==', user.uid)));
    if (snap.empty) { container.innerHTML = '<p class="info-text" style="font-size:13px">Nemate stanove.</p>'; return; }
    container.innerHTML = snap.docs.map(d => `
      <label class="report-check">
        <input type="checkbox" class="rp-unit-cb" value="${d.id}"
          data-name="${d.data().name}" data-owner="${user.uid}" data-owner-name="" checked>
        ${d.data().name}${d.data().adresa ? ' — ' + d.data().adresa : ''}
      </label>
    `).join('');
  } catch(e) {
    container.innerHTML = '<p class="info-text" style="font-size:13px;color:var(--red)">Greška pri učitavanju.</p>';
  }
}

// ── Odredi raspon datuma ─────────────────────────────────────────
function getPeriodRange(period) {
  let od, do_;
  const now = new Date();
  if (period === 'month') {
    const val = document.getElementById('rpMonth').value; // "2025-06"
    const [y, m] = val.split('-').map(Number);
    od  = new Date(y, m - 1, 1);
    do_ = new Date(y, m, 0, 23, 59, 59);
  } else if (period === 'quarter') {
    const q    = parseInt(document.getElementById('rpQuarter').value);
    const year = parseInt(document.getElementById('rpQuarterYear').value);
    const startMonth = (q - 1) * 3;
    od  = new Date(year, startMonth, 1);
    do_ = new Date(year, startMonth + 3, 0, 23, 59, 59);
  } else if (period === 'year') {
    const year = parseInt(document.getElementById('rpYear').value);
    od  = new Date(year, 0, 1);
    do_ = new Date(year, 11, 31, 23, 59, 59);
  } else {
    od  = new Date(document.getElementById('rpDateOd').value);
    do_ = new Date(document.getElementById('rpDateDo').value);
    do_.setHours(23, 59, 59);
  }
  return { od, do_ };
}

// ── Formatiranje ─────────────────────────────────────────────────
function fmtDate(ts) {
  if (!ts) return '—';
  const d = ts.toDate ? ts.toDate() : new Date(ts);
  return d.toLocaleDateString('sr-Latn', { day: '2-digit', month: '2-digit', year: 'numeric' });
}
function fmtAmt(iznos, valuta) {
  return iznos.toLocaleString('sr-Latn', { maximumFractionDigits: 2 }) + ' ' + (valuta || 'RSD');
}
function periodLabel(period) {
  if (period === 'month') {
    const val = document.getElementById('rpMonth').value;
    const [y, m] = val.split('-').map(Number);
    const ime = new Date(y, m-1, 1).toLocaleDateString('sr-Latn', { month: 'long', year: 'numeric' });
    return ime.charAt(0).toUpperCase() + ime.slice(1);
  } else if (period === 'quarter') {
    return `Q${document.getElementById('rpQuarter').value} ${document.getElementById('rpQuarterYear').value}`;
  } else if (period === 'year') {
    return document.getElementById('rpYear').value;
  } else {
    return `${document.getElementById('rpDateOd').value} – ${document.getElementById('rpDateDo').value}`;
  }
}

// ── Glavni generator ─────────────────────────────────────────────
async function generateReport(user, period) {
  const btn    = document.getElementById('rpGenerateBtn');
  const status = document.getElementById('rpStatus');
  btn.disabled = true;
  status.textContent = 'Učitavam podatke...';

  try {
    const unitIds = [...document.querySelectorAll('.rp-unit-cb:checked')].map(cb => ({
      id: cb.value,
      name: cb.dataset.name,
      ownerUid: cb.dataset.owner || user.uid,
      ownerName: cb.dataset.ownerName || ''
    }));
    if (!unitIds.length) { alert('Izaberi bar jedan stan.'); btn.disabled = false; status.textContent = ''; return; }

    const { od, do_ } = getPeriodRange(period);
    const secs = {
      zakupac:  document.getElementById('rpSecZakupac').checked,
      prihodi:  document.getElementById('rpSecPrihodi').checked,
      troskovi: document.getElementById('rpSecTroskovi').checked,
      kvarovi:  document.getElementById('rpSecKvarovi').checked,
      poruke:   document.getElementById('rpSecPoruke').checked,
    };

    // Učitaj profil korisnika koji generiše izveštaj
    const userDoc = await getDoc(doc(db, 'users', user.uid));
    const reporterName = userDoc.exists() ? (userDoc.data().displayName || user.email) : user.email;

    // Učitaj podatke za svaki stan
    const unitDataArr = [];
    for (const u of unitIds) {
      status.textContent = `Učitavam: ${u.name}...`;
      const unitSnap = await getDoc(doc(db, 'units', u.id));
      const unit = unitSnap.exists() ? unitSnap.data() : {};

      let prihodi = [], troskovi = [], kvarovi = [], poruke = [];

      if (secs.prihodi) {
        try {
          const snap = await getDocs(collection(db, 'units', u.id, 'income'));
          snap.forEach(d => {
            const dt = d.data().datum?.toDate ? d.data().datum.toDate() : null;
            if (dt && dt >= od && dt <= do_) prihodi.push(d.data());
          });
          prihodi.sort((a,b) => (a.datum?.toDate?.() || 0) - (b.datum?.toDate?.() || 0));
        } catch(e) { console.error('PRIHODI failed:', e.message); }
      }
      if (secs.troskovi) {
        try {
          const snap = await getDocs(collection(db, 'units', u.id, 'expenses'));
          snap.forEach(d => {
            const dt = d.data().datum?.toDate ? d.data().datum.toDate() : null;
            if (dt && dt >= od && dt <= do_) troskovi.push(d.data());
          });
          troskovi.sort((a,b) => (a.datum?.toDate?.() || 0) - (b.datum?.toDate?.() || 0));
        } catch(e) { console.error('TROSKOVI failed:', e.message); }
      }
      if (secs.kvarovi) {
        try {
          const snap = await getDocs(query(collection(db, 'kvarovi'), where('ownerId', '==', user.uid)));

          snap.forEach(d => {
            const kd = d.data();

            if (kd.unitId !== u.id) return;
            const dt = kd.vreme?.toDate ? kd.vreme.toDate() : null;

            if (dt && dt >= od && dt <= do_) kvarovi.push(kd);
          });
          kvarovi.sort((a, b) => {
            const ta = a.vreme?.toDate ? a.vreme.toDate() : new Date(0);
            const tb = b.vreme?.toDate ? b.vreme.toDate() : new Date(0);
            return ta - tb;
          });
        } catch(e) { console.error('KVAROVI failed:', e.message); }
      }
      if (secs.poruke) {
        try {
          const snap = await getDocs(collection(db, 'units', u.id, 'messages'));
          snap.forEach(d => {
            const dt = d.data().vreme?.toDate ? d.data().vreme.toDate() : null;
            if (dt && dt >= od && dt <= do_) poruke.push(d.data());
          });
          poruke.sort((a,b) => (a.vreme?.toDate?.() || 0) - (b.vreme?.toDate?.() || 0));
        } catch(e) { console.error('PORUKE failed:', e.message); }
      }

      unitDataArr.push({ id: u.id, name: u.name, unit, prihodi, troskovi, kvarovi, poruke });
    }

    status.textContent = 'Generišem PDF...';
    await buildPDF(reporterName, user.email, period, od, do_, secs, unitDataArr);
    status.textContent = 'PDF je preuzet.';
    setTimeout(() => { status.textContent = ''; }, 3000);
  } catch(e) {
    console.error(e);
    status.textContent = 'Greška: ' + e.message;
  }
  btn.disabled = false;
}

// ── PDF Builder (jsPDF) ──────────────────────────────────────────
async function buildPDF(reporterName, reporterEmail, period, od, do_, secs, units) {
  // Dinamički učitaj jsPDF
  if (!window.jspdf) {
    await new Promise((res, rej) => {
      const s = document.createElement('script');
      s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';
      s.onload = res; s.onerror = rej;
      document.head.appendChild(s);
    });
  }
  const { jsPDF } = window.jspdf;
  const landlordName = reporterName;
const landlordEmail = reporterEmail;
const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

  // Učitaj DejaVu Sans fontove sa GitHub Pages
  let FONT = 'helvetica';
  try {
    const toB64 = async (url) => {
      const resp  = await fetch(url);
      const buf   = await resp.arrayBuffer();
      const bytes = new Uint8Array(buf);
      let b64 = '';
      const chunk = 8192;
      for (let i = 0; i < bytes.length; i += chunk)
        b64 += String.fromCharCode(...bytes.subarray(i, i + chunk));
      return btoa(b64);
    };
    const [b64Regular, b64Bold] = await Promise.all([
      toB64('./fonts/DejaVuSans.ttf'),
      toB64('./fonts/DejaVuSans-Bold.ttf')
    ]);
    pdf.addFileToVFS('DejaVuSans.ttf', b64Regular);
    pdf.addFont('DejaVuSans.ttf', 'DejaVuSans', 'normal');
    pdf.addFileToVFS('DejaVuSans-Bold.ttf', b64Bold);
    pdf.addFont('DejaVuSans-Bold.ttf', 'DejaVuSans', 'bold');
    FONT = 'DejaVuSans';
  } catch(e) {
    console.warn('Font load failed, koristim Helvetica:', e.message);
  }
  
  const W = 210, H = 297;
  const ML = 15, MR = 15, MT = 15;
  const CW = W - ML - MR;
  let y = MT;

  const COL_ACCENT  = [220, 50, 90];
  const COL_DARK    = [30, 30, 40];
  const COL_MUTED   = [110, 110, 125];
  const COL_BORDER  = [210, 210, 220];
  const COL_BG_SEC  = [245, 245, 250];
  const COL_BG_ALT  = [250, 250, 255];
  const COL_WHITE   = [255, 255, 255];
  const COL_GREEN   = [40, 167, 80];
  const COL_RED     = [200, 50, 60];

  let pageNum = 1;

  function addPageNum() {
    pdf.setFont(FONT, 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(...COL_MUTED);
    pdf.text(`${pageNum}`, W / 2, H - 8, { align: 'center' });
    pdf.text('Rental Manager — Izveštaj', ML, H - 8);
    pdf.text(new Date().toLocaleDateString('sr-Latn'), W - MR, H - 8, { align: 'right' });
  }

  function checkPageBreak(needed = 10) {
    if (y + needed > H - 18) {
      addPageNum();
      pdf.addPage();
      pageNum++;
      y = MT;
      return true;
    }
    return false;
  }

  function drawSectionHeader(title) {
    checkPageBreak(14);
    pdf.setFillColor(...COL_ACCENT);
    pdf.roundedRect(ML, y, CW, 8, 1.5, 1.5, 'F');
    pdf.setFont(FONT, 'bold');
    pdf.setFontSize(9);
    pdf.setTextColor(...COL_WHITE);
    pdf.text(title.toUpperCase(), ML + 4, y + 5.5);
    y += 11;
  }

  function drawSubHeader(title) {
    checkPageBreak(10);
    pdf.setFillColor(...COL_BG_SEC);
    pdf.rect(ML, y, CW, 7, 'F');
    pdf.setFont(FONT, 'bold');
    pdf.setFontSize(8.5);
    pdf.setTextColor(...COL_DARK);
    pdf.text(title, ML + 3, y + 5);
    y += 9;
  }

  function drawRow(cols, widths, opts = {}) {
    const rowH = opts.rowH || 7;
    checkPageBreak(rowH);
    if (opts.bg) {
      pdf.setFillColor(...opts.bg);
      pdf.rect(ML, y, CW, rowH, 'F');
    }
    if (opts.border) {
      pdf.setDrawColor(...COL_BORDER);
      pdf.setLineWidth(0.2);
      pdf.line(ML, y + rowH, ML + CW, y + rowH);
    }
    let x = ML + 2;
    cols.forEach((col, i) => {
      const w = widths[i];
      pdf.setFont(FONT, opts.bold ? 'bold' : 'normal');
      pdf.setFontSize(8);
      pdf.setTextColor(...(opts.color || COL_DARK));
      const align = opts.aligns?.[i] || 'left';
      if (align === 'right') {
        pdf.text(String(col), x + w - 4, y + 5, { align: 'right' });
      } else {
        // Skrati tekst ako je predugačak
        let txt = String(col);
        while (pdf.getTextWidth(txt) > w - 4 && txt.length > 3) txt = txt.slice(0, -1);
        if (txt !== String(col)) txt = txt.slice(0, -2) + '...';
        pdf.text(txt, x, y + 5);
      }
      x += w;
    });
    y += rowH;
  }

  function drawInfoRow(label, value) {
    checkPageBreak(7);
    pdf.setFont(FONT, 'bold');
    pdf.setFontSize(8);
    pdf.setTextColor(...COL_MUTED);
    pdf.text(label + ':', ML + 2, y + 4.5);
    pdf.setFont(FONT, 'normal');
    pdf.setTextColor(...COL_DARK);
    pdf.text(String(value || '—'), ML + 42, y + 4.5);
    y += 6.5;
  }

  function gap(n = 4) { y += n; }

  // ════════════════════════════════════════════
  // NASLOVNA STRANA
  // ════════════════════════════════════════════
  
  // Logo
  try {
    pdf.addImage(LOGO_B64, 'PNG', ML, y, 18, 18);
  } catch(e) {}

  // Naziv aplikacije
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(20);
  pdf.setTextColor(...COL_ACCENT);
  pdf.text('Rental Manager', ML + 22, y + 8);
  pdf.setFont(FONT, 'normal');
  pdf.setFontSize(10);
  pdf.setTextColor(...COL_MUTED);
  pdf.text('Izveštaj o poslovanju', ML + 22, y + 15);
  y += 25;

  // Linija
  pdf.setDrawColor(...COL_ACCENT);
  pdf.setLineWidth(0.5);
  pdf.line(ML, y, W - MR, y);
  y += 8;

  // Landlord info
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(13);
  pdf.setTextColor(...COL_DARK);
  pdf.text(landlordName, ML, y);
  y += 6;
  pdf.setFont(FONT, 'normal');
  pdf.setFontSize(9);
  pdf.setTextColor(...COL_MUTED);
  pdf.text(landlordEmail, ML, y);
  y += 10;

  // Period info box
  pdf.setFillColor(...COL_BG_SEC);
  pdf.roundedRect(ML, y, CW, 22, 2, 2, 'F');
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(9);
  pdf.setTextColor(...COL_MUTED);
  pdf.text('PERIOD IZVEŠTAJA', ML + 5, y + 7);
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(13);
  pdf.setTextColor(...COL_DARK);
  pdf.text(periodLabel(period), ML + 5, y + 15);
  const periodRange = `${od.toLocaleDateString('sr-Latn')} – ${do_.toLocaleDateString('sr-Latn')}`;
  pdf.setFont(FONT, 'normal');
  pdf.setFontSize(8);
  pdf.setTextColor(...COL_MUTED);
  pdf.text(periodRange, W - MR - 5, y + 15, { align: 'right' });
  y += 28;

  // Stanovi u izveštaju — grupisani po landlordovima
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(9);
  pdf.setTextColor(...COL_MUTED);
  pdf.text(`STANOVI U IZVEŠTAJU (${units.length})`, ML, y);
  y += 6;

  // Grupiši po ownerUid
  const ownerGroups = {};
  units.forEach(u => {
    const key = u.ownerUid || 'unknown';
    if (!ownerGroups[key]) ownerGroups[key] = { name: u.ownerName || u.ownerUid || '—', units: [] };
    ownerGroups[key].units.push(u);
  });

  Object.values(ownerGroups).forEach(group => {
    checkPageBreak(8);
    pdf.setFont(FONT, 'bold');
    pdf.setFontSize(8.5);
    pdf.setTextColor(...COL_ACCENT);
    pdf.text(group.name, ML + 2, y);
    y += 5;
    group.units.forEach(u => {
      checkPageBreak(5);
      pdf.setFont(FONT, 'normal');
      pdf.setFontSize(8);
      pdf.setTextColor(...COL_DARK);
      pdf.text(`    • ${u.name}${u.unit.adresa ? '  –  ' + u.unit.adresa : ''}`, ML + 2, y);
      y += 4.5;
    });
    y += 2;
  });
  y += 3;

  // Sekcije
  pdf.setFont(FONT, 'bold');
  pdf.setFontSize(8);
  pdf.setTextColor(...COL_MUTED);
  const secLabels = [];
  if (secs.zakupac)  secLabels.push('Zakupac');
  if (secs.prihodi)  secLabels.push('Prihodi');
  if (secs.troskovi) secLabels.push('Troškovi');
  if (secs.kvarovi)  secLabels.push('Kvarovi');
  if (secs.poruke)   secLabels.push('Poruke');
  pdf.text('Sadržaj: ' + secLabels.join(' · '), ML, y);

  addPageNum();

  // ════════════════════════════════════════════
  // PO STANU
  // ════════════════════════════════════════════
  for (const u of units) {
    pdf.addPage();
    pageNum++;
    y = MT;

    // Stan header
    pdf.setFillColor(...COL_DARK);
    pdf.roundedRect(ML, y, CW, 20, 2, 2, 'F');
    try { pdf.addImage(LOGO_B64, 'PNG', ML + 3, y + 2, 16, 16); } catch(e) {}
    pdf.setFont(FONT, 'bold');
    pdf.setFontSize(14);
    pdf.setTextColor(...COL_WHITE);
    pdf.text(u.name, ML + 23, y + 9);
    pdf.setFont(FONT, 'normal');
    pdf.setFontSize(8.5);
    pdf.setTextColor(200, 200, 210);
    pdf.text([u.unit.adresa, u.unit.kvadratura ? u.unit.kvadratura + ' m²' : null].filter(Boolean).join('   ·   '), ML + 23, y + 16);
    pdf.setFont(FONT, 'normal');
    pdf.setFontSize(8);
    pdf.setTextColor(180, 180, 195);
    pdf.text(periodLabel(period), W - MR - 3, y + 9, { align: 'right' });
    y += 26;

    // ── ZAKUPAC ──
    if (secs.zakupac) {
      drawSectionHeader('Zakupac');
      drawInfoRow('Ime i prezime', u.unit.zakupacIme);
      drawInfoRow('E-mail', u.unit.tenantEmail);
      if (u.unit.zakupacDok) drawInfoRow('Dokument', u.unit.zakupacDok);
      if (u.unit.zakupOd || u.unit.zakupDo)
        drawInfoRow('Period zakupa', `${u.unit.zakupOd || '—'} → ${u.unit.zakupDo || '—'}`);
      if (u.unit.rent) drawInfoRow('Mesečna renta', fmtAmt(u.unit.rent, 'RSD'));
      gap(3);
    }

    // ── PRIHODI ──
    if (secs.prihodi) {
      drawSectionHeader('Prihodi');
      if (!u.prihodi.length) {
        pdf.setFont(FONT, 'normal'); pdf.setFontSize(8); pdf.setTextColor(...COL_MUTED);
        pdf.text('Nema prihoda u izabranom periodu.', ML + 3, y + 4); y += 9;
      } else {
        drawRow(['Datum', 'Napomena', 'Iznos'], [30, 105, 45], { bold: true, bg: COL_BG_SEC, color: COL_MUTED });
        let total = 0;
        u.prihodi.forEach((p, i) => {
          drawRow(
            [fmtDate(p.datum), p.napomena || '—', fmtAmt(p.iznos, p.valuta)],
            [30, 105, 45],
            { bg: i % 2 === 0 ? COL_WHITE : COL_BG_ALT, border: true, aligns: ['left','left','right'] }
          );
          total += p.iznos || 0;
        });
        drawRow(['', 'UKUPNO', fmtAmt(total, u.prihodi[0]?.valuta || 'RSD')], [30, 105, 45],
          { bold: true, bg: [230,245,235], color: COL_GREEN, aligns: ['left','left','right'] });
      }
      gap(4);
    }

    // ── TROŠKOVI ──
    if (secs.troskovi) {
      drawSectionHeader('Troškovi');
      const fiksni = u.troskovi.filter(t => t.kategorija === 'fiksni');
      const varij  = u.troskovi.filter(t => t.kategorija !== 'fiksni');

      if (!u.troskovi.length) {
        pdf.setFont(FONT, 'normal'); pdf.setFontSize(8); pdf.setTextColor(...COL_MUTED);
        pdf.text('Nema troškova u izabranom periodu.', ML + 3, y + 4); y += 9;
      } else {
        if (fiksni.length) {
          drawSubHeader('Fiksni troškovi');
          drawRow(['Datum', 'Vrsta', 'Napomena', 'Iznos'], [28, 40, 82, 30],
            { bold: true, bg: COL_BG_SEC, color: COL_MUTED });
          let tot = 0;
          fiksni.forEach((t, i) => {
            drawRow(
              [fmtDate(t.datum), FIXED_LABELS[t.vrsta] || t.vrsta, t.napomena || '—', fmtAmt(t.iznos, t.valuta)],
              [28, 40, 82, 30],
              { bg: i % 2 === 0 ? COL_WHITE : COL_BG_ALT, border: true, aligns: ['left','left','left','right'] }
            );
            tot += t.iznos || 0;
          });
          drawRow(['', '', 'UKUPNO', fmtAmt(tot, fiksni[0]?.valuta || 'RSD')], [28, 40, 82, 30],
            { bold: true, bg: [250,235,235], color: COL_RED, aligns: ['left','left','left','right'] });
          gap(3);
        }
        if (varij.length) {
          drawSubHeader('Varijabilni troškovi');
          drawRow(['Datum', 'Vrsta', 'Napomena', 'Iznos'], [28, 40, 82, 30],
            { bold: true, bg: COL_BG_SEC, color: COL_MUTED });
          let tot = 0;
          varij.forEach((t, i) => {
            drawRow(
              [fmtDate(t.datum), VAR_LABELS[t.vrsta] || t.vrsta, t.napomena || '—', fmtAmt(t.iznos, t.valuta)],
              [28, 40, 82, 30],
              { bg: i % 2 === 0 ? COL_WHITE : COL_BG_ALT, border: true, aligns: ['left','left','left','right'] }
            );
            tot += t.iznos || 0;
          });
          drawRow(['', '', 'UKUPNO', fmtAmt(tot, varij[0]?.valuta || 'RSD')], [28, 40, 82, 30],
            { bold: true, bg: [250,235,235], color: COL_RED, aligns: ['left','left','left','right'] });
        }
      }
      gap(4);
    }

    // ── KVAROVI ──
    if (secs.kvarovi) {
      drawSectionHeader('Prijave kvarova');
      if (!u.kvarovi.length) {
        pdf.setFont(FONT, 'normal'); pdf.setFontSize(8); pdf.setTextColor(...COL_MUTED);
        pdf.text('Nema prijava kvarova u izabranom periodu.', ML + 3, y + 4); y += 9;
      } else {
        drawRow(['Datum', 'Opis', 'Hitnost', 'Status'], [28, 90, 27, 35],
          { bold: true, bg: COL_BG_SEC, color: COL_MUTED });
        u.kvarovi.forEach((k, i) => {
          const statusLabel = k.status === 'reseno' ? 'Rešeno' : k.status === 'ceka_validaciju' ? 'Čeka val.' : 'Otvoreno';
          drawRow(
            [fmtDate(k.vreme), k.stavka + (k.opis ? ': ' + k.opis : ''), k.hitnost || '—', statusLabel],
            [28, 90, 27, 35],
            { bg: i % 2 === 0 ? COL_WHITE : COL_BG_ALT, border: true }
          );
        });
      }
      gap(4);
    }

    // ── PORUKE ──
    if (secs.poruke) {
      drawSectionHeader('Komunikacija');
      if (!u.poruke.length) {
        pdf.setFont(FONT, 'normal'); pdf.setFontSize(8); pdf.setTextColor(...COL_MUTED);
        pdf.text('Nema poruka u izabranom periodu.', ML + 3, y + 4); y += 9;
      } else {
        u.poruke.forEach((m, i) => {
          checkPageBreak(12);
          const sender = m.displayName ? m.displayName.split(' ')[0] : (m.od || '').split('@')[0];
          const time = m.vreme?.toDate ? m.vreme.toDate().toLocaleString('sr-Latn', { day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit' }) : '—';
          pdf.setFillColor(...(i % 2 === 0 ? COL_WHITE : COL_BG_ALT));
          pdf.rect(ML, y, CW, 10, 'F');
          pdf.setFont(FONT, 'bold');
          pdf.setFontSize(7.5);
          pdf.setTextColor(...COL_ACCENT);
          pdf.text(sender, ML + 2, y + 4.5);
          pdf.setFont(FONT, 'normal');
          pdf.setFontSize(7.5);
          pdf.setTextColor(...COL_MUTED);
          pdf.text(time, W - MR - 2, y + 4.5, { align: 'right' });
          pdf.setFont(FONT, 'normal');
          pdf.setFontSize(8);
          pdf.setTextColor(...COL_DARK);
          let txt = m.tekst || '';
          if (pdf.getTextWidth(txt) > CW - 30) txt = txt.slice(0, 80) + '...';
          pdf.text(txt, ML + 2, y + 8.5);
          pdf.setDrawColor(...COL_BORDER);
          pdf.setLineWidth(0.15);
          pdf.line(ML, y + 10, ML + CW, y + 10);
          y += 10;
        });
      }
    }

    addPageNum();
  }

  // Preuzmi
  const fname = `rental-report-${new Date().toISOString().slice(0,10)}.pdf`;
  pdf.save(fname);
}
